import pytest
import torch
import ttnn

from .layer_norm import layer_norm


def pytorch_reference(input_tensor, residual_tensor, weight_tensor, bias_tensor):
    """PyTorch reference for this stage."""
    x = input_tensor.float() + residual_tensor.float()
    return torch.nn.functional.layer_norm(
        x,
        (x.shape[-1],),
        weight=weight_tensor.float().reshape(-1),
        bias=bias_tensor.float().reshape(-1),
        eps=1e-5,
    )


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 96), id="1x1x32x96"),
        pytest.param((2, 3, 64, 70), id="2x3x64x70"),
    ],
)
def test_residual_affine(device, shape):
    """Verify Add residual reread and row-broadcast affine streams on top of the base normalization path.."""
    layout = ttnn.TILE_LAYOUT
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma_shape = [1] * len(shape)
    gamma_shape[-1] = shape[-1]
    torch_residual = torch.randn(shape, dtype=torch.bfloat16)
    torch_weight = torch.randn(tuple(gamma_shape), dtype=torch.bfloat16)
    torch_bias = torch.randn(tuple(gamma_shape), dtype=torch.bfloat16)

    expected = pytorch_reference(
        torch_input,
        residual_tensor=torch_residual,
        weight_tensor=torch_weight,
        bias_tensor=torch_bias,
    )

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    ttnn_residual = ttnn.from_torch(
        torch_residual,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    ttnn_weight = ttnn.from_torch(
        torch_weight,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    ttnn_bias = ttnn.from_torch(
        torch_bias,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm(
        ttnn_input,
        epsilon=1e-5,
        residual_input_tensor=ttnn_residual,
        weight=ttnn_weight,
        bias=ttnn_bias,
    )

    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
